import{_ as e,o as a,c as o,ag as r}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"🧠 The 5-Step Framework","description":"","frontmatter":{},"headers":[],"relativePath":"framework.md","filePath":"framework.md"}'),n={name:"framework.md"};function s(i,t,d,l,p,c){return a(),o("div",null,[...t[0]||(t[0]=[r(`<h1 id="🧠-the-5-step-framework" tabindex="-1">🧠 The 5-Step Framework <a class="header-anchor" href="#🧠-the-5-step-framework" aria-label="Permalink to &quot;🧠 The 5-Step Framework&quot;">​</a></h1><blockquote><p>Before touching code, follow this loop for every single problem. Interviewers score your <strong>process</strong> as heavily as your answer.</p></blockquote><hr><h2 id="the-loop" tabindex="-1">The Loop <a class="header-anchor" href="#the-loop" aria-label="Permalink to &quot;The Loop&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Step</th><th>Action</th><th>Time to spend</th></tr></thead><tbody><tr><td>1</td><td><strong>Understand</strong> — restate, examples, constraints</td><td>2–3 min</td></tr><tr><td>2</td><td><strong>Brute force</strong> — state it out loud</td><td>1–2 min</td></tr><tr><td>3</td><td><strong>Pattern</strong> — identify the right approach</td><td>2–3 min</td></tr><tr><td>4</td><td><strong>Code</strong> — clean, readable, no tricks</td><td>10–15 min</td></tr><tr><td>5</td><td><strong>Test</strong> — trace + edge cases</td><td>2–3 min</td></tr></tbody></table><hr><h2 id="step-1-—-understand-the-problem" tabindex="-1">Step 1 — Understand the Problem <a class="header-anchor" href="#step-1-—-understand-the-problem" aria-label="Permalink to &quot;Step 1 — Understand the Problem&quot;">​</a></h2><p>Never assume. Ask or state:</p><ul><li>What are the input types and sizes? (<code>n ≤ 10^5</code>?)</li><li>Can there be duplicates? Negatives? Null?</li><li>Is there always exactly one answer?</li><li>What should I return — indices, values, count?</li><li>Are elements sorted?</li></ul><p><strong>Say it back:</strong> <em>&quot;So I&#39;m given an array of integers and a target, and I need to return the indices of two numbers that add up to the target. There&#39;s always exactly one solution, and I can&#39;t use the same element twice. Did I get that right?&quot;</em></p><hr><h2 id="step-2-—-state-the-brute-force" tabindex="-1">Step 2 — State the Brute Force <a class="header-anchor" href="#step-2-—-state-the-brute-force" aria-label="Permalink to &quot;Step 2 — State the Brute Force&quot;">​</a></h2><p>Always do this. Even if you immediately know the optimal solution.</p><p><strong>Why:</strong> It shows you understand the problem. It gives you a baseline complexity to beat. It buys you time to think.</p><p><em>&quot;The naive approach is two nested loops — try every pair. That&#39;s O(n²) time, O(1) space. I can do better.&quot;</em></p><hr><h2 id="step-3-—-spot-the-pattern" tabindex="-1">Step 3 — Spot the Pattern <a class="header-anchor" href="#step-3-—-spot-the-pattern" aria-label="Permalink to &quot;Step 3 — Spot the Pattern&quot;">​</a></h2><p>Ask these questions in order:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Is the input sorted?           → Binary search or two pointers</span></span>
<span class="line"><span>Need a subarray/substring?     → Sliding window</span></span>
<span class="line"><span>Need pair/complement lookup?   → HashMap (O(1) lookup)</span></span>
<span class="line"><span>Tree or graph traversal?       → BFS (shortest) or DFS (explore all)</span></span>
<span class="line"><span>Generating all combinations?   → Backtracking</span></span>
<span class="line"><span>Optimal substructure?          → Dynamic programming</span></span>
<span class="line"><span>Need kth largest/smallest?     → Heap (priority queue)</span></span>
<span class="line"><span>Ranges/intervals overlapping?  → Sort + merge</span></span>
<span class="line"><span>Linked list cycle/middle?      → Fast &amp; slow pointer</span></span>
<span class="line"><span>Next greater/smaller element?  → Monotonic stack</span></span>
<span class="line"><span>Cumulative range queries?      → Prefix sum</span></span></code></pre></div><hr><h2 id="step-4-—-write-clean-code" tabindex="-1">Step 4 — Write Clean Code <a class="header-anchor" href="#step-4-—-write-clean-code" aria-label="Permalink to &quot;Step 4 — Write Clean Code&quot;">​</a></h2><p>Rules while coding:</p><ul><li><strong>Name variables clearly.</strong> <code>left</code>, <code>right</code>, <code>complement</code> — not <code>l</code>, <code>r</code>, <code>c</code>.</li><li><strong>No clever one-liners.</strong> Write it like a junior will maintain it.</li><li><strong>Comment your intent</strong> on non-obvious lines.</li><li><strong>Write the brute force first</strong> if you&#39;re stuck. Optimization can come after.</li></ul><hr><h2 id="step-5-—-test-trace" tabindex="-1">Step 5 — Test &amp; Trace <a class="header-anchor" href="#step-5-—-test-trace" aria-label="Permalink to &quot;Step 5 — Test &amp; Trace&quot;">​</a></h2><p>Never say &quot;I think this works.&quot; Always:</p><ol><li>Trace through the given example by hand</li><li>Test these edge cases: <ul><li>Empty input (<code>[]</code>)</li><li>Single element (<code>[5]</code>)</li><li>All same elements (<code>[3,3,3]</code>)</li><li>Minimum/maximum values</li><li>Negative numbers (if applicable)</li></ul></li></ol><hr><h2 id="complexity-cheat-sheet" tabindex="-1">Complexity Cheat Sheet <a class="header-anchor" href="#complexity-cheat-sheet" aria-label="Permalink to &quot;Complexity Cheat Sheet&quot;">​</a></h2><p>Know this cold. If you can&#39;t state the Big O, you can&#39;t defend your solution.</p><table tabindex="0"><thead><tr><th>Complexity</th><th>What it means</th><th>Typical algorithm</th></tr></thead><tbody><tr><td><code>O(1)</code></td><td>Constant — doesn&#39;t grow</td><td>HashMap lookup, array index</td></tr><tr><td><code>O(log n)</code></td><td>Halving each step</td><td>Binary search, balanced BST</td></tr><tr><td><code>O(n)</code></td><td>Single pass</td><td>Two pointers, sliding window, BFS/DFS</td></tr><tr><td><code>O(n log n)</code></td><td>Sort-based</td><td>Merge sort, most sorting problems</td></tr><tr><td><code>O(n²)</code></td><td>Nested loops</td><td>Brute force pair-checking</td></tr><tr><td><code>O(2ⁿ)</code></td><td>Doubling per step</td><td>Backtracking subsets</td></tr><tr><td><code>O(n!)</code></td><td>All arrangements</td><td>Permutations</td></tr></tbody></table><hr><h2 id="the-acceptable-complexities-by-input-size" tabindex="-1">The &quot;Acceptable&quot; Complexities by Input Size <a class="header-anchor" href="#the-acceptable-complexities-by-input-size" aria-label="Permalink to &quot;The &quot;Acceptable&quot; Complexities by Input Size&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Input size <code>n</code></th><th>Max acceptable complexity</th></tr></thead><tbody><tr><td><code>n ≤ 10</code></td><td>O(n!) or O(2ⁿ) fine</td></tr><tr><td><code>n ≤ 20</code></td><td>O(2ⁿ) fine</td></tr><tr><td><code>n ≤ 100</code></td><td>O(n³) fine</td></tr><tr><td><code>n ≤ 1,000</code></td><td>O(n²) fine</td></tr><tr><td><code>n ≤ 100,000</code></td><td>O(n log n) required</td></tr><tr><td><code>n ≤ 1,000,000</code></td><td>O(n) or O(n log n) required</td></tr></tbody></table><hr><h2 id="what-to-say-when-stuck" tabindex="-1">What to Say When Stuck <a class="header-anchor" href="#what-to-say-when-stuck" aria-label="Permalink to &quot;What to Say When Stuck&quot;">​</a></h2><p>Don&#39;t go silent. Narrate your thinking:</p><ol><li><em>&quot;Let me think about what information I need at each step...&quot;</em></li><li><em>&quot;If I had a data structure that could tell me X in O(1)...&quot;</em></li><li><em>&quot;What if I processed from both ends simultaneously?&quot;</em></li><li><em>&quot;Can I precompute something to make each lookup faster?&quot;</em></li><li><em>&quot;This feels like it might have overlapping subproblems — maybe DP?&quot;</em></li></ol><p>Silence kills interviews. Narration saves them.</p>`,39)])])}const m=e(n,[["render",s]]);export{u as __pageData,m as default};
